public boolean hasDuplicate(int[] nums) {
    Set<Integer> seen = new HashSet<>();
    for (int n : nums) {
        if (seen.contains(n)) {
            return true;
        }
        seen.add(n);
    }
    return false;
}

public boolean isAnagram(String s, String t) {
    char[] sArray = s.toCharArray();
    char[] tArray = t.toCharArray();
    Arrays.sort(sArray);
    Arrays.sort(tArray);
    String sSorted = new String(sArray);
    String tSorted = new String(tArray);
    return sSorted.equals(tSorted);
}

public int[] twoSum(int[] nums, int target) {
    Map<Integer, Integer> indices = new HashMap<>();
    for (int i = 0; i < nums.length; i++) {
        indices.put(nums[i], i);
    }
    for (int i = 0; i < nums.length; i++) {
        int diff = target - nums[i];
        if (indices.containsKey(diff) && indices.get(diff) != i) {
            return new int[]{i, indices.get(diff)};
        }
    }
    return new int[0];
}

public int longestConsecutive(int[] nums) {
    if (nums.length == 0) return 0;
    HashSet<Integer> set = new HashSet<Integer>();
    for (int num : nums) set.add(num);
    int result = 0;
    for (int num : set) {
        if (!set.contains(num - 1)) {
            int currentNum = num;
            int current = 1;
            while (set.contains(currentNum + 1)) {
                currentNum++;
                current++;
            }
            result = Math.max(result, current);
        }
    }
    return result;
}

public boolean isValid(String s) {
    Stack<Character> stack = new Stack<>();
    Map<Character, Character> closeToOpen = new HashMap<>();
    closeToOpen.put(')', '(');
    closeToOpen.put(']', '[');
    closeToOpen.put('}', '{');
    for (char c : s.toCharArray()) {
        if (closeToOpen.containsKey(c)) {
            if (!stack.isEmpty() && stack.peek() == closeToOpen.get(c)) {
                stack.pop();
            } else {
                return false;
            }
        } else {
            stack.push(c);
        }
    }
    return stack.isEmpty();
}

public boolean isPalindrome(String s) {
    int l = 0, r = s.length() - 1;
    while (l < r) {
        while (l < r && !alphaNum(s.charAt(l))) {
            l++;
        }
        while (r > l && !alphaNum(s.charAt(r))) {
            r--;
        }
        if (Character.toLowerCase(s.charAt(l)) != Character.toLowerCase(s.charAt(r))) {
            return false;
        }
        l++; r--;
    }
    return true;
}
public boolean alphaNum(char c) {
    return (c >= 'A' && c <= 'Z' ||
            c >= 'a' && c <= 'z' ||
            c >= '0' && c <= '9');
}

public List<List<String>> groupAnagrams(String[] strs) {
    Map<String, List<String>> res = new HashMap<>();
    for (String s : strs) {
        char[] charArray = s.toCharArray();
        Arrays.sort(charArray);
        String sortedS = new String(charArray);
        res.putIfAbsent(sortedS, new ArrayList<>());
        res.get(sortedS).add(s);
    }
    return new ArrayList<>(res.values());
}

public class Node {
    int key;
    int val;
    Node prev;
    Node next;
    public Node(int key, int val) {
        this.key = key;
        this.val = val;
        this.prev = null;
        this.next = null;
    }
}
class LRUCache {
    private int cap;
    private HashMap<Integer, Node> cache;
    private Node left;
    private Node right;
    public LRUCache(int capacity) {
        this.cap = capacity;
        this.cache = new HashMap<>();
        this.left = new Node(0, 0);
        this.right = new Node(0, 0);
        this.left.next = this.right;
        this.right.prev = this.left;
    }
    public void remove(Node node) {
        Node prev = node.prev;
        Node next = node.next;
        prev.next = next;
        next.prev = prev;
    }
    public void insert(Node node) {
        Node prev = this.right.prev;
        prev.next = node;
        node.prev = prev;
        node.next = this.right;
        this.right.prev = node;
    }
}

class LRUCache {
    public int get(int key) {
        if (!cache.containsKey(key)) return -1;
        Node node = cache.get(key);
        remove(node);
        insert(node);
        return node.val;
    }
    public void put(int key, int value) {
        if (cache.containsKey(key)) {
            remove(cache.get(key));
        }
        Node newNode = new Node(key, value);
        cache.put(key, newNode);
        insert(newNode);
        if (cache.size() > cap) {
            Node lru = this.left.next;
            remove(lru);
            cache.remove(lru.key);
        }
    }
}

class Solution {
    class FrequencyValue {
        private int frequency;
        private int value;
        public FrequencyValue(int frequency, int value) {
            this.frequency = frequency;
            this.value = value;
        }
        public int getFrequency() {
            return frequency;
        }
    }
    public int[] topKFrequent(int[] nums, int k) {
        Map<Integer, Integer> counter = new HashMap<>();
        PriorityQueue<FrequencyValue> heap = new PriorityQueue<>(Comparator.comparingInt(FrequencyValue::getFrequency));
        for (int num : nums) {
            counter.put(num, counter.getOrDefault(num, 0) + 1);
        }
        for (Map.Entry<Integer, Integer> entry : counter.entrySet()) {
            heap.offer(new FrequencyValue(entry.getValue(), entry.getKey()));
            if (heap.size() > k) {
                heap.poll();
            }
        }
        int[] result = new int[k];
        for (int i = 0; i < k; i++) {
            result[i] = heap.poll().value;
        }
        return result;
    }
}

class KthLargest {
    private PriorityQueue<Integer> minHeap;
    private int k;
    public KthLargest(int k, int[] nums) {
        this.k = k;
        this.minHeap = new PriorityQueue<>();
        for (int n : nums) {
            minHeap.offer(n);
            if (minHeap.size() > k) {
                minHeap.poll();
            }
        }
    }
    public int add(int val) {
        this.minHeap.offer(val);
        if (this.minHeap.size() > k) {
            this.minHeap.poll();
        }
        return minHeap.peek();
    }
}

public class Solution {
    class Move {
        int row;
        int col;
        Move(int row, int col) {
            this.row = row;
            this.col = col;
        }
    }

    private final Move[] directions = {
        new Move(1, 0), new Move(-1, 0),
        new Move(0, 1), new Move(0, -1)
    };

    public int numIslands(char[][] grid) {
        int ROWS = grid.length, COLS = grid[0].length;
        int islands = 0;

        for (int r = 0; r < ROWS; r++) {
            for (int c = 0; c < COLS; c++) {
                if (grid[r][c] == '1') {
                    dfs(grid, r, c);
                    islands++;
                }
            }
        }

        return islands;
    }

    private void dfs(char[][] grid, int r, int c) {
        if (r < 0 || c < 0 || r >= grid.length ||
            c >= grid[0].length || grid[r][c] == '0') {
            return;
        }

        grid[r][c] = '0';
        for (Move dir : directions) {
            dfs(grid, r + dir.row, c + dir.col);
        }
    }
}

public class Solution {
    class Move {
        int row;
        int col;
        Move(int row, int col) {
            this.row = row;
            this.col = col;
        }
    }

    private final Move[] directions = {
        new Move(1, 0), new Move(-1, 0),
        new Move(0, 1), new Move(0, -1)
    };

    public int numIslands(char[][] grid) {
        int ROWS = grid.length, COLS = grid[0].length;
        int islands = 0;

        for (int r = 0; r < ROWS; r++) {
            for (int c = 0; c < COLS; c++) {
                if (grid[r][c] == '1') {
                    bfs(grid, r, c);
                    islands++;
                }
            }
        }

        return islands;
    }

    private void bfs(char[][] grid, int r, int c) {
        Queue<Move> q = new LinkedList<>();
        grid[r][c] = '0';
        q.add(new Move(r, c));

        while (!q.isEmpty()) {
            Move node = q.poll();
            int row = node.row, col = node.col;

            for (Move dir : directions) {
                int nr = row + dir.row, nc = col + dir.col;
                if (nr >= 0 && nc >= 0 && nr < grid.length &&
                    nc < grid[0].length && grid[nr][nc] == '1') {
                    q.add(new Move(nr, nc));
                    grid[nr][nc] = '0';
                }
            }
        }
    }
}
